1	// --- Domain types ---
2	type Customer = { yearsWithMHPCO: number };
3	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Damage = { itemType: string; amount: number };
6	type Incident = { cause: string; damages: Damage[] };
7	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
8	type Step = QuoteStep | ClaimStep;
9	type Scenario = { customer: Customer; steps: Step[] };
10	
11	type QuoteResult = { premium: number };
12	type ClaimResult = { payout: number; remainingCap: number };
13	type StepResult = QuoteResult | ClaimResult;
14	
15	// --- Pricing constants ---
16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_SURCHARGE = 0.1;
18	const LOYALTY_DISCOUNT = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const FOLLOWUP_DISCOUNT = 0.15;
21	const CURSE_SURCHARGE = 0.5;
22	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	const BLOCK_BASE = 60;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	const DEDUCTIBLE = 100;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const INSURANCE_VALUES: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	
46	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
47	const insuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
48	
49	const roundUp = (n: number): number => Math.ceil(Math.round(n * 1e6) / 1e6);
50	
51	const countByType = (items: Item[]): Record<string, number> => {
52	  const counts: Record<string, number> = {};
53	  for (const item of items) {
54	    counts[item.type] = (counts[item.type] ?? 0) + 1;
55	  }
56	  return counts;
57	};
58	
59	const groupBasePrice = (type: string, count: number): number => {
60	  const lineTotal = basePremium({ type }) * count;
61	  const blockApplies = COMPONENT_TYPES.has(type) && count === 3;
62	  return blockApplies ? BLOCK_BASE : lineTotal;
63	};
64	
65	const itemBaseTotal = (items: Item[]): number =>
66	  Object.entries(countByType(items)).reduce(
67	    (sum, [type, count]) => sum + groupBasePrice(type, count),
68	    0,
69	  );
70	
71	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
72	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
73	  {
74	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
75	    rate: HIGH_ENCHANTMENT_SURCHARGE,
76	  },
77	];
78	
79	const itemSurchargeRate = (item: Item): number =>
80	  SURCHARGE_RULES.reduce((rate, rule) => (rule.applies(item) ? rate + rule.rate : rate), 0);
81	
82	const itemSurcharges = (items: Item[]): number =>
83	  items.reduce((sum, item) => sum + basePremium(item) * itemSurchargeRate(item), 0);
84	
85	const policyModifierRate = (customer: Customer, quoteIndex: number): number => {
86	  let rate = 0;
87	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
88	  if (quoteIndex > 0) rate -= FOLLOWUP_DISCOUNT;
89	  return rate;
90	};
91	
92	const KNOWN_TYPES = new Set(Object.keys(BASE_PREMIUMS));
93	
94	const quotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
95	  for (const item of items) {
96	    if (!KNOWN_TYPES.has(item.type)) {
97	      throw new Error(`unknown item type: ${item.type}`);
98	    }
99	  }
100	  const baseTotal = itemBaseTotal(items);
101	  const firstInsurance = baseTotal * FIRST_INSURANCE_SURCHARGE;
102	  const policyModifier = baseTotal * policyModifierRate(customer, quoteIndex);
103	  const beforeFee = baseTotal + firstInsurance + itemSurcharges(items) + policyModifier;
104	  return roundUp(beforeFee + PROCESSING_FEE);
105	};
106	
107	type Policy = { items: Item[]; capRemaining: number };
108	
109	const insuranceSum = (items: Item[]): number =>
110	  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
111	
112	const newPolicy = (items: Item[]): Policy => ({
113	  items,
114	  capRemaining: 2 * insuranceSum(items),
115	});
116	
117	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
118	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
119	
120	const reimbursableAmount = (item: Item, damage: Damage): number => {
121	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
122	    return damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE;
123	  }
124	  return damage.amount;
125	};
126	
127	const damagePayout = (item: Item, damage: Damage): number =>
128	  Math.max(0, reimbursableAmount(item, damage) - DEDUCTIBLE);
129	
130	const damagePayoutFor = (policy: Policy, damage: Damage): number => {
131	  const item = policy.items.find((i) => i.type === damage.itemType)!;
132	  return damagePayout(item, damage);
133	};
134	
135	const uncappedPayout = (policy: Policy, incident: Incident): number =>
136	  incident.damages.reduce((sum, damage) => sum + damagePayoutFor(policy, damage), 0);
137	
138	const validateIncident = (policy: Policy, incident: Incident): void => {
139	  const insuredCounts = countByType(policy.items);
140	  const damageCounts: Record<string, number> = {};
141	  for (const damage of incident.damages) {
142	    if (damage.amount < 0) {
143	      throw new Error(`damage amount must be non-negative, got ${damage.amount}`);
144	    }
145	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
146	  }
147	  for (const [type, count] of Object.entries(damageCounts)) {
148	    if (count > (insuredCounts[type] ?? 0)) {
149	      throw new Error(
150	        `claim damages ${count} ${type}(s) but policy insures ${insuredCounts[type] ?? 0}`,
151	      );
152	    }
153	  }
154	};
155	
156	const settleClaim = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
157	  validateIncident(policy, incident);
158	  const payout = Math.floor(Math.min(uncappedPayout(policy, incident), policy.capRemaining));
159	  const capRemaining = policy.capRemaining - payout;
160	  return { result: { payout, remainingCap: capRemaining }, policy: { ...policy, capRemaining } };
161	};
162	
163	export const run = (scenario: Scenario): { results: StepResult[] } => {
164	  const policies: Policy[] = [];
165	  const results: StepResult[] = [];
166	  for (const step of scenario.steps) {
167	    if (step.op === "quote") {
168	      results.push({ premium: quotePremium(step.items, scenario.customer, policies.length) });
169	      policies.push(newPolicy(step.items));
170	    } else {
171	      const { result, policy } = settleClaim(policies[step.policy], step.incident);
172	      policies[step.policy] = policy;
173	      results.push(result);
174	    }
175	  }
176	  return { results };
177	};
