3	const readStdin = async (): Promise<string> => {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) chunks.push(chunk as Buffer);
6	  return Buffer.concat(chunks).toString("utf8");
7	};
8	
9	const main = async () => {
10	  try {
11	    const input = await readStdin();
12	    const scenario = JSON.parse(input);
13	    const output = run(scenario);
14	    process.stdout.write(JSON.stringify(output));
15	  } catch (err) {
16	    const message = err instanceof Error ? err.message : String(err);
17	    process.stderr.write(`${message}\n`);
18	    process.exit(1);
19	  }
20	};
21	
22	await main();
